+                                    base_id,
+                                    schema,
+                                    target_table,
+                                    linked_record,
+                                    Some(config),
+                                    Some(state),
+                                    depth_remaining.saturating_sub(1),
+                                    true,
+                                )
+                                .await?,
+                            );
+                        }
+                        Err(AirtableError::Api {
+                            status_code: Some(404),
+                            ..
+                        })
