+                        "linked_table": {
+                            "id": target_table.id,
+                            "name": target_table.name,
+                        },
+                        "partial": partial,
+                        "records": resolved_records,
+                    }),
+                );
+            }
+
+            Ok(linked_records)
+        })
+    }
